{
  "name": "National Family Caregiver Support Program (NFCSP)",
  "eligibility": {
    "age": 60,
    "income_limits": "No income limits for core benefits; prioritizes caregivers of older individuals with greatest social need and greatest economic need, but services available without strict cutoffs[3][5]",
    "asset_limits": "No asset limits mentioned[5]",
    "other_requirements": [
      "Family caregiver 18+ caring for person 60+ or with Alzheimer’s/dementia of any age[3]",
      "Parent or relative caregiver 55+ living with and primary caregiver for adult 18+ with disabilities[3]",
      "Older relative caregiver (not parent) 55+ living with and primary caregiver for child 18 or younger[3]",
      "Unpaid family member or close friend providing assistance to person 60+ or with disabilities[5]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Information and assistance gaining access to services; individual counseling; support groups or caregiver training; respite care; supplemental services[3][8]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Contact local Area Agency on Aging via 211[5]",
      "Contact Idaho Commission on Aging or local AAA through aging.idaho.gov[5][8]"
    ],
    "processing_time": "Not specified in available data",
    "waitlist": null,
    "forms": ["AAA National Family Caregiver Support Program Worksheet (internal AAA use)[3]"],
    "documents": ["Eligibility assessment completed via intake; no specific documents listed, prepare proof of relationship and care needs"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered through local Area Agencies on Aging (AAAs)[3][5][8]",
    "regional_variations": "Access varies: Boise (full in-person training, respite grants); Northern Idaho (strong telehealth, grants); Eastern (hospital integration, end-of-life workshops); Southern (rural mobile units, prioritized respite)[5]",
    "offices_or_providers": ["Local Area Agencies on Aging; contact via 211 or aging.idaho.gov[5][8]"]
  },
  "official_source": "https://aging.idaho.gov/stay-at-home/national-family-caregiver-support-program/",
  "gotchas": [
    "Does not provide direct payments to family caregivers; focuses on support services like respite and training, not compensation[2][4]",
    "Prioritizes those with greatest social/economic need, but no strict income test—availability may depend on funding and local AAA capacity[3]",
    "Not a Medicaid payment program; for paid care, pursue separate Certified Family Home or agency employment options[2][4]",
    "Regional delivery differences may affect in-person vs. telehealth access[5]"
  ],
  "data_shape_notes": "No income/asset tests; services via local AAAs with regional variations in delivery (e.g., mobile units in rural areas); prioritizes by need tier without fixed hours/dollars; no direct pay"
}

{
  "name": "Idaho Legal Aid Services",
  "eligibility": {
    "age": 60,
    "income_limits": "Income must be below 125% of the 2024 Federal Poverty Guidelines (exact dollar amounts not specified in sources; older 2015 figures from guidebook: $1,265 for single person, $1,705 for couple). Limits vary by household size per federal guidelines[1][9].",
    "asset_limits": "Resources or assets below $5,000 (2015 figure; what counts and exemptions not detailed)[1].",
    "other_requirements": ["Low-income status", "Idaho resident", "U.S. citizen", "Civil legal issues only (e.g., elder abuse, evictions, benefits access)", "Priority for income, health care, housing, abuse/neglect cases[4][6]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free civil legal assistance including advice, counseling, representation by attorney or paralegal; stops elder abuse/financial fraud, prevents wrongful evictions, ensures access to Medicare/Medicaid/Social Security, drafts estate-planning tools, community clinics on scams[2][4][6]. No specific dollar amounts or hours stated.",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: Idaho Senior Legal Hotline 866-345-0106[4]", "Website: https://idaholegalaid.org (apply online via legal help section)[6]", "In-person: Local offices statewide[7][8]", "Contact local Area Agency on Aging offices[7]"],
    "processing_time": "Not specified in sources",
    "waitlist": null,
    "forms": ["Not specified; provide proof of income, case info, ID during intake[3]"],
    "documents": ["Proof of income", "Information about legal case", "Personal identification", "Asset/resource details if applicable[3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available throughout Idaho; some partnerships county-specific (e.g., Area IV: Blaine, Camas, Cassia, Gooding, Jerome, Lincoln, Minidoka, Twin Falls)[4][8]",
    "regional_variations": "Local offices and Area Agency partnerships may affect access; priority services via regional contacts[4][7]",
    "offices_or_providers": ["Network of local offices statewide; partners with Area Agencies on Aging and CSI Office on Aging (208-736-2122 for Area IV)[4][7][8]"]
  },
  "official_source": "https://idaholegalaid.org",
  "gotchas": ["Outdated income/asset figures in guidebook (2015); current is 125% FPL 2024[1][9]", "Civil cases only; no criminal[3][6]", "Must meet exact eligibility screening; alternatives like pro bono if ineligible[3]", "Priority for urgent issues like abuse, housing[4]"],
  "data_shape_notes": "Income at 125% federal poverty guidelines (varies by household size); age 60+ priority for seniors; statewide with regional offices and partnerships; no fixed hours/dollars, service-based by priority"
}

{
  "name": "LEARN Idaho Senior Education Programs",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to seniors 60+ for free education per state aging commission and university policies, with no financial tests mentioned[5][3]",
    "asset_limits": "No asset limits or tests apply[5]",
    "other_requirements": ["Idaho resident for certain programs like Boise State senior audits (age 65+)[3][5]", "No formal application for most free access; space-available registration[3][5]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free auditing of university classes (Boise State: no charge for Idaho residents 65+, credit classes full price); TechEd classes on elder care and digital literacy; online handouts and in-person technology training; community educational programs on retirement, aging, caregiving[2][3][5]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Online: learnidaho.org/teched for TechEd classes[5]", "University admission as nondegree student then register (Boise State)[3]", "In-person: local providers like LEARN Idaho meetings and classes[2][5]", "Phone/website: aging.idaho.gov for resources[5]"],
    "processing_time": "Immediate for online/resources; space permits during open enrollment for university audits[3]",
    "waitlist": "Space-available basis, potential wait for in-person classes[3][5]",
    "forms": ["Boise State nondegree admission application[3]"],
    "documents": ["Proof of age (65+ for audits), Idaho residency[3][5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; online statewide via LEARN Idaho[5]",
    "regional_variations": "Western (Treasure Valley): LEARN Idaho TechEd in-person/online; Northern: NIC free audits; Southern: Boise State audits; Eastern/Western: more online[5]",
    "offices_or_providers": ["LEARN Idaho (learnidaho.org)[2][5]", "Boise State University[3]", "Idaho Commission on Aging (aging.idaho.gov)[5]"]
  },
  "official_source": "https://learnidaho.org/",
  "gotchas": ["Not a single formal 'program' with income/assets test—decentralized free education opportunities; audits are non-credit only for free (credit full price)[3][5]", "Membership for professionals, not seniors (for access to content)[2]", "Rural areas limited to online; in-person urban-focused[5]", "Space-available, not guaranteed enrollment[3]"],
  "data_shape_notes": "Decentralized network of free senior learning via universities, LEARN Idaho, and aging resources; varies heavily by region (in-person urban, online rural); no income/asset test, age 60+/65+ residency focus[5]"
}

{
  "name": "EICAP Senior Housing Program",
  "eligibility": {
    "age": 62,
    "income_limits": "Must meet income limits (exact dollar amounts not specified in sources; typically low-income thresholds like under $1,473/month for household of one or $1,984/month for two, aligned with 30% Area Median Income or HUD guidelines for seniors).[3][4]",
    "asset_limits": "Not specified in sources.",
    "other_requirements": ["Disabled individuals also qualify regardless of age.", "Tenant selection criteria (details not specified).", "Must meet general low-income housing guidelines, such as HUD income limits."][4][5]
  },
  "benefits": {
    "type": "in_kind",
    "value": "Affordable senior housing units (92 units total across properties); provides housing for low-income seniors at reduced rent based on income (typically ~30% of adjusted gross monthly income). Specific properties: Riverside Senior Housing (Idaho Falls), South Fremont Senior Housing (St. Anthony), Teton View Senior Housing (Idaho Falls).",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Phone: Riverside and Teton View Senior Housing at (208) 716-8692.", "Phone: South Fremont Senior Housing at (208) 624-7206.", "Contact housing units directly for applications (in-person or mail implied). No online application specified."],
    "processing_time": "Not specified.",
    "waitlist": "Waiting lists vary by location (similar to other Idaho programs with 12-18 month averages).",
    "forms": ["Not specified; submit application to property manager."],
    "documents": ["Income verification.", "Rental references.", "ID (state ID, driver’s license).", "Social Security cards.", "Birth certificates for children (if applicable).", "Immigration documents if applicable (I-94, EAD, Permanent Resident Card)."][1]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Eastern Idaho only (serves 9 counties). Limited to specific properties in Idaho Falls and St. Anthony.",
    "regional_variations": "Housing owned and managed by EICAP in Idaho Falls (Riverside, Teton View) and St. Anthony (South Fremont); different phone numbers per property; wait times vary by location.",
    "offices_or_providers": ["Riverside Senior Housing, 450 J Street, Idaho Falls, ID 83402.", "South Fremont Senior Housing, 835 West Main, St. Anthony, ID 83445.", "Teton View Senior Housing, 1550 Teton View Lane, Idaho Falls, ID 83402."]
  },
  "official_source": "https://www.eicap.org/housing/",
  "gotchas": ["Assistance stays with the apartment/unit (not portable/transferable like HCV vouchers).", "Must contact specific property directly—central EICAP application not available.", "Age sometimes listed as 60+ in senior services context, but senior housing specifies 62+ or disabled.", "Tenant selection criteria beyond income/age not detailed—may include background checks.", "Waiting lists common and vary by property/location."],
  "data_shape_notes": "Regionally restricted to Eastern Idaho (Idaho Falls and St. Anthony properties only); owned/managed by EICAP with property-specific contacts; income-based rent (~30% AGI); not statewide or portable."
}
